from flask import Flask, request, jsonify
import numpy as np
from collections import defaultdict

app = Flask(__name__)

# Store image labels
image_labels = defaultdict(list)

@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_id = data.get('image_id')
    label = data.get('label')
    
    if not image_id or label is None:
        return jsonify({"error": "image_id and label are required"}), 400
    
    image_labels[image_id].append(label)
    return jsonify({"message": "Label received"}), 200

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    for image_id, labels in image_labels.items():
        majority_label = max(set(labels), key=labels.count)
        aggregated_labels[image_id] = majority_label
    return jsonify(aggregated_labels), 200

